CREATE OR REPLACE FUNCTION fpb_get_prename_group_by_lon (as_loan_no text) RETURNS varchar AS $body$
DECLARE

  ls_prename_group varchar(30);
  ls_group_no varchar(15);
  ls_mem_no varchar(15);

BEGIN
  ls_mem_no := pka_com_function.fp_get_loan_memno(as_loan_no);
  ls_group_no := pka_com_function.fp_get_member_group(ls_mem_no);

  select pre_group_name into STRICT ls_prename_group from sc_mem_m_ucf_member_group  where trim(both member_group_no) = trim(both ls_group_no);
  if coalesce(ls_prename_group::text, '') = '' then
    ls_prename_group := 'no_data';
  end if;
  return ls_prename_group;

exception WHEN OTHERS then CALL spa_dberror('FPB_GET_PRENAME_GROUP_BY_LON');return ' ';
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
